import { TrackingResult, TrackingParams, VideoInfo } from '../../types';

declare global {
  interface Window {
    cv: any;
  }
}

export class CVEngine {
  private bgSubtractor: any = null;
  private morphKernel: any = null;
  private staticBackground: any = null;
  
  private threshold: number = 50;
  private minArea: number = 100;
  private maxArea: number = 10000;
  private blurKernelSize: number = 21;
  private fps: number = 30;
  
  private useStaticBackground: boolean = false;
  private isInitialized: boolean = false;
  private initPromise: Promise<void> | null = null;

  constructor() {
    this.initPromise = this.initOpenCV();
  }

  private async initOpenCV(): Promise<void> {
    return new Promise((resolve, reject) => {
      const checkCV = () => {
        if (typeof window.cv !== 'undefined' && window.cv.getBuildInformation) {
          try {
            this.bgSubtractor = new window.cv.BackgroundSubtractorMOG2(500, 50, false);
            this.morphKernel = window.cv.getStructuringElement(
              window.cv.MORPH_ELLIPSE,
              new window.cv.Size(5, 5)
            );
            this.isInitialized = true;
            resolve();
          } catch (err) {
            reject(err);
          }
        } else if (typeof window.cv !== 'undefined') {
          window.cv.onRuntimeInitialized = () => {
            try {
              this.bgSubtractor = new window.cv.BackgroundSubtractorMOG2(500, 50, false);
              this.morphKernel = window.cv.getStructuringElement(
                window.cv.MORPH_ELLIPSE,
                new window.cv.Size(5, 5)
              );
              this.isInitialized = true;
              resolve();
            } catch (err) {
              reject(err);
            }
          };
        } else {
          setTimeout(checkCV, 100);
        }
      };
      checkCV();
    });
  }

  async waitForInit(): Promise<void> {
    if (this.isInitialized) return;
    if (this.initPromise) await this.initPromise;
  }

  setParameters(params: Partial<TrackingParams>): void {
    if (params.threshold !== undefined) this.threshold = params.threshold;
    if (params.minArea !== undefined) this.minArea = params.minArea;
    if (params.maxArea !== undefined) this.maxArea = params.maxArea;
    if (params.blurKernelSize !== undefined) this.blurKernelSize = params.blurKernelSize;
    if (params.fps !== undefined) this.fps = params.fps;
  }

  setStaticBackground(backgroundImage: ImageData): void {
    if (!this.isInitialized) return;
    
    const src = window.cv.matFromImageData(backgroundImage);
    const gray = new window.cv.Mat();
    
    window.cv.cvtColor(src, gray, window.cv.COLOR_RGBA2GRAY);
    window.cv.GaussianBlur(
      gray,
      gray,
      new window.cv.Size(this.blurKernelSize, this.blurKernelSize),
      0
    );
    
    this.staticBackground = gray;
    this.useStaticBackground = true;
    src.delete();
  }

  clearStaticBackground(): void {
    if (this.staticBackground) {
      this.staticBackground.delete();
      this.staticBackground = null;
    }
    this.useStaticBackground = false;
  }

  processFrame(imageData: ImageData, frameNumber: number): TrackingResult {
    if (!this.isInitialized) {
      return {
        frame: frameNumber,
        timestamp: frameNumber / this.fps,
        x: 0,
        y: 0,
        detected: false,
        area: 0,
        velocity: 0
      };
    }

    const src = window.cv.matFromImageData(imageData);
    const gray = new window.cv.Mat();
    const blurred = new window.cv.Mat();
    const fgMask = new window.cv.Mat();

    window.cv.cvtColor(src, gray, window.cv.COLOR_RGBA2GRAY);
    window.cv.GaussianBlur(
      gray,
      blurred,
      new window.cv.Size(this.blurKernelSize, this.blurKernelSize),
      0
    );

    if (this.useStaticBackground && this.staticBackground) {
      const diff = new window.cv.Mat();
      window.cv.absdiff(this.staticBackground, blurred, diff);
      window.cv.threshold(diff, fgMask, this.threshold, 255, window.cv.THRESH_BINARY);
      diff.delete();
    } else {
      this.bgSubtractor.apply(blurred, fgMask);
    }

    window.cv.morphologyEx(fgMask, fgMask, window.cv.MORPH_OPEN, this.morphKernel);
    window.cv.morphologyEx(fgMask, fgMask, window.cv.MORPH_CLOSE, this.morphKernel);

    const contours = new window.cv.MatVector();
    const hierarchy = new window.cv.Mat();
    window.cv.findContours(
      fgMask,
      contours,
      hierarchy,
      window.cv.RETR_EXTERNAL,
      window.cv.CHAIN_APPROX_SIMPLE
    );

    let centroid: { x: number; y: number } | null = null;
    let maxArea = 0;

    for (let i = 0; i < contours.size(); i++) {
      const contour = contours.get(i);
      const area = window.cv.contourArea(contour);

      if (area >= this.minArea && area <= this.maxArea && area > maxArea) {
        const moments = window.cv.moments(contour);
        if (moments.m00 !== 0) {
          maxArea = area;
          centroid = {
            x: moments.m10 / moments.m00,
            y: moments.m01 / moments.m00
          };
        }
      }
    }

    src.delete();
    gray.delete();
    blurred.delete();
    fgMask.delete();
    contours.delete();
    hierarchy.delete();

    return {
      frame: frameNumber,
      timestamp: frameNumber / this.fps,
      x: centroid?.x ?? 0,
      y: centroid?.y ?? 0,
      detected: centroid !== null,
      area: maxArea,
      velocity: 0
    };
  }

  processFrameWithBinary(
    imageData: ImageData,
    frameNumber: number
  ): { result: TrackingResult; binaryData: ImageData | null } {
    if (!this.isInitialized) {
      return {
        result: {
          frame: frameNumber,
          timestamp: frameNumber / this.fps,
          x: 0,
          y: 0,
          detected: false,
          area: 0,
          velocity: 0
        },
        binaryData: null
      };
    }

    const src = window.cv.matFromImageData(imageData);
    const gray = new window.cv.Mat();
    const blurred = new window.cv.Mat();
    const fgMask = new window.cv.Mat();

    window.cv.cvtColor(src, gray, window.cv.COLOR_RGBA2GRAY);
    window.cv.GaussianBlur(
      gray,
      blurred,
      new window.cv.Size(this.blurKernelSize, this.blurKernelSize),
      0
    );

    if (this.useStaticBackground && this.staticBackground) {
      const diff = new window.cv.Mat();
      window.cv.absdiff(this.staticBackground, blurred, diff);
      window.cv.threshold(diff, fgMask, this.threshold, 255, window.cv.THRESH_BINARY);
      diff.delete();
    } else {
      this.bgSubtractor.apply(blurred, fgMask);
    }

    window.cv.morphologyEx(fgMask, fgMask, window.cv.MORPH_OPEN, this.morphKernel);
    window.cv.morphologyEx(fgMask, fgMask, window.cv.MORPH_CLOSE, this.morphKernel);

    const contours = new window.cv.MatVector();
    const hierarchy = new window.cv.Mat();
    window.cv.findContours(
      fgMask,
      contours,
      hierarchy,
      window.cv.RETR_EXTERNAL,
      window.cv.CHAIN_APPROX_SIMPLE
    );

    let centroid: { x: number; y: number } | null = null;
    let maxArea = 0;

    for (let i = 0; i < contours.size(); i++) {
      const contour = contours.get(i);
      const area = window.cv.contourArea(contour);

      if (area >= this.minArea && area <= this.maxArea && area > maxArea) {
        const moments = window.cv.moments(contour);
        if (moments.m00 !== 0) {
          maxArea = area;
          centroid = {
            x: moments.m10 / moments.m00,
            y: moments.m01 / moments.m00
          };
        }
      }
    }

    const binaryData = this.matToImageData(fgMask);

    src.delete();
    gray.delete();
    blurred.delete();
    fgMask.delete();
    contours.delete();
    hierarchy.delete();

    return {
      result: {
        frame: frameNumber,
        timestamp: frameNumber / this.fps,
        x: centroid?.x ?? 0,
        y: centroid?.y ?? 0,
        detected: centroid !== null,
        area: maxArea,
        velocity: 0
      },
      binaryData
    };
  }

  private matToImageData(mat: any): ImageData | null {
    if (!mat || mat.rows === 0 || mat.cols === 0) return null;

    const canvas = document.createElement('canvas');
    canvas.width = mat.cols;
    canvas.height = mat.rows;
    const ctx = canvas.getContext('2d');
    if (!ctx) return null;

    const rgba = new window.cv.Mat();
    window.cv.cvtColor(mat, rgba, window.cv.COLOR_GRAY2RGBA);
    
    const imageData = ctx.createImageData(mat.cols, mat.rows);
    imageData.data.set(rgba.data);
    
    rgba.delete();
    return imageData;
  }

  static getVideoInfo(video: HTMLVideoElement): VideoInfo {
    return {
      width: video.videoWidth,
      height: video.videoHeight,
      fps: 30,
      duration: video.duration,
      frameCount: Math.floor(video.duration * 30)
    };
  }

  destroy(): void {
    if (this.bgSubtractor) {
      this.bgSubtractor.delete();
    }
    if (this.morphKernel) {
      this.morphKernel.delete();
    }
    if (this.staticBackground) {
      this.staticBackground.delete();
    }
    this.isInitialized = false;
  }
}

export const cvEngine = new CVEngine();
