import React, { useState, useMemo } from 'react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const StatusIndicator = ({ label, value, icon, color }) => (
  <div className="status-indicator" style={{ borderColor: color }}>
    <div className="status-header">
      <span className="status-icon">{icon}</span>
      <span className="status-label">{label}</span>
    </div>
    <div className="status-value" style={{ color }}>
      {value}
    </div>
  </div>
);

const MetricCard = ({ label, value, unit, trend, icon }) => (
  <div className="metric-card">
    <div className="metric-header">
      <span className="metric-icon">{icon}</span>
      <span className="metric-label">{label}</span>
    </div>
    <div className="metric-body">
      <span className="metric-value">{value}</span>
      <span className="metric-unit">{unit}</span>
    </div>
    {trend !== undefined && (
      <div className={`metric-trend ${trend >= 0 ? 'positive' : 'negative'}`}>
        {trend >= 0 ? '↑' : '↓'} {Math.abs(trend)}%
      </div>
    )}
  </div>
);

const TrajectoryChart = ({ trajectory, videoInfo }) => {
  const data = useMemo(() => {
    if (!trajectory || trajectory.length === 0) {
      return {
        labels: [],
        datasets: []
      };
    }

    return {
      labels: trajectory.map((_, i) => i),
      datasets: [
        {
          label: 'X 坐标',
          data: trajectory.map(p => p.x),
          borderColor: 'rgb(255, 99, 132)',
          backgroundColor: 'rgba(255, 99, 132, 0.1)',
          tension: 0.3,
          fill: false
        },
        {
          label: 'Y 坐标',
          data: trajectory.map(p => p.y),
          borderColor: 'rgb(54, 162, 235)',
          backgroundColor: 'rgba(54, 162, 235, 0.1)',
          tension: 0.3,
          fill: false
        }
      ]
    };
  }, [trajectory]);

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: {
          color: '#fff',
          font: { size: 10 }
        }
      }
    },
    scales: {
      x: {
        display: false
      },
      y: {
        grid: {
          color: 'rgba(255, 255, 255, 0.1)'
        },
        ticks: {
          color: '#888',
          font: { size: 10 }
        }
      }
    }
  };

  return (
    <div className="trajectory-chart">
      <Line data={data} options={options} />
    </div>
  );
};

const HeatmapDisplay = ({ rois, trackingData, videoInfo }) => {
  const heatmapData = useMemo(() => {
    if (!trackingData || !rois || rois.length === 0) {
      return null;
    }
    
    return rois.map(roi => {
      const timeInROI = trackingData.trajectory?.filter(p => {
        return isPointInROI(p, roi);
      }).length * 0.033 || 0;
      
      return {
        name: roi.name,
        time: timeInROI.toFixed(1),
        percentage: ((timeInROI / (videoInfo?.duration || 1)) * 100).toFixed(1)
      };
    });
  }, [trackingData, rois, videoInfo]);

  const isPointInROI = (point, roi) => {
    if (roi.type === 'rectangle') {
      return point.x >= roi.x && 
             point.x <= roi.x + roi.width &&
             point.y >= roi.y && 
             point.y <= roi.y + roi.height;
    } else if (roi.type === 'circle') {
      const distance = Math.sqrt(
        Math.pow(point.x - roi.center.x, 2) + 
        Math.pow(point.y - roi.center.y, 2)
      );
      return distance <= roi.radius;
    }
    return false;
  };

  if (!heatmapData || heatmapData.length === 0) {
    return (
      <div className="heatmap-empty">
        <p>暂无热力数据</p>
        <p className="hint">绘制区域后开始追踪</p>
      </div>
    );
  }

  return (
    <div className="heatmap-display">
      {heatmapData.map((item, index) => (
        <div key={index} className="heatmap-bar">
          <div className="heatmap-label">{item.name}</div>
          <div className="heatmap-progress">
            <div 
              className="heatmap-fill"
              style={{ 
                width: `${item.percentage}%`,
                backgroundColor: `hsl(${200 - item.percentage * 2}, 70%, 50%)`
              }}
            />
          </div>
          <div className="heatmap-time">{item.time}s ({item.percentage}%)</div>
        </div>
      ))}
    </div>
  );
};

const DataPanel = ({
  experimentType,
  trackingData,
  rois,
  currentTime,
  currentFrame,
  isTracking,
  subjectInfo,
  scaleCalibration
}) => {
  const [activeTab, setActiveTab] = useState('trajectory');
  const [isExporting, setIsExporting] = useState(false);

  const metrics = useMemo(() => {
    if (!trackingData) {
      return {
        totalDistance: 0,
        avgSpeed: 0,
        centerTime: 0,
        entries: 0,
        immobilityTime: 0,
        maxSpeed: 0
      };
    }

    const trajectory = trackingData.trajectory || [];
    let totalDistance = 0;
    let speeds = [];
    let immobilityFrames = 0;

    for (let i = 1; i < trajectory.length; i++) {
      const dx = trajectory[i].x - trajectory[i-1].x;
      const dy = trajectory[i].y - trajectory[i-1].y;
      const distance = Math.sqrt(dx * dx + dy * dy);
      
      if (scaleCalibration) {
        totalDistance += distance / scaleCalibration.pixelsPerCm;
      } else {
        totalDistance += distance;
      }
      
      const speed = distance * 30;
      speeds.push(speed);
      
      if (distance < 1) {
        immobilityFrames++;
      }
    }

    const avgSpeed = speeds.length > 0 
      ? speeds.reduce((a, b) => a + b, 0) / speeds.length 
      : 0;
    const maxSpeed = speeds.length > 0 
      ? Math.max(...speeds) 
      : 0;
    const immobilityTime = immobilityFrames * 0.033;

    return {
      totalDistance: totalDistance.toFixed(1),
      avgSpeed: avgSpeed.toFixed(1),
      centerTime: '0.0',
      entries: 0,
      immobilityTime: immobilityTime.toFixed(1),
      maxSpeed: maxSpeed.toFixed(1)
    };
  }, [trackingData, scaleCalibration]);

  const currentStatus = useMemo(() => {
    if (trackingData?.currentLocation || trackingData?.currentZone || trackingData?.status || trackingData?.currentState) {
      return {
        location: trackingData.currentLocation || trackingData.currentZone || '未知区域',
        state: trackingData.status || trackingData.currentState || '等待追踪'
      };
    }

    if (!trackingData?.trajectory || trackingData.trajectory.length === 0) {
      return {
        location: '未知区域',
        state: '等待追踪'
      };
    }

    const lastPoint = trackingData.trajectory[trackingData.trajectory.length - 1];
    let location = '未知区域';
    
    for (const roi of rois) {
      if (isPointInROI(lastPoint, roi)) {
        location = roi.name;
        break;
      }
    }

    const prevPoint = trackingData.trajectory[trackingData.trajectory.length - 2];
    const dx = lastPoint.x - (prevPoint?.x || lastPoint.x);
    const dy = lastPoint.y - (prevPoint?.y || lastPoint.y);
    const movement = Math.sqrt(dx * dx + dy * dy);
    
    const state = movement < 2 ? '静止中' : '运动中';

    return { location, state };
  }, [trackingData, rois]);

  function isPointInROI(point, roi) {
    if (roi.type === 'rectangle') {
      return point.x >= roi.x && 
             point.x <= roi.x + roi.width &&
             point.y >= roi.y && 
             point.y <= roi.y + roi.height;
    } else if (roi.type === 'circle') {
      const distance = Math.sqrt(
        Math.pow(point.x - roi.center.x, 2) + 
        Math.pow(point.y - roi.center.y, 2)
      );
      return distance <= roi.radius;
    }
    return false;
  }

  const handleExport = async () => {
    setIsExporting(true);
    
    try {
      const exportData = {
        experimentType: experimentType?.name,
        subjectInfo,
        rois,
        metrics,
        trackingData,
        scaleCalibration,
        exportTime: new Date().toISOString()
      };

      const blob = new Blob([JSON.stringify(exportData, null, 2)], {
        type: 'application/json'
      });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `analysis_report_${subjectInfo.id || 'unknown'}_${Date.now()}.json`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      await new Promise(resolve => setTimeout(resolve, 500));
    } catch (error) {
      console.error('Export failed:', error);
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="data-panel">
      <div className="panel-header">
        <h3>数据看板</h3>
        <span className={`tracking-status ${isTracking ? 'active' : ''}`}>
          {isTracking ? '追踪中' : '待机'}
        </span>
      </div>

      <div className="status-section">
        <StatusIndicator
          label="所在区域"
          value={currentStatus.location}
          icon="📍"
          color="#4facfe"
        />
        <StatusIndicator
          label="当前状态"
          value={currentStatus.state}
          icon="⚡"
          color="#00f260"
        />
      </div>

      <div className="metrics-section">
        <h4 className="section-title">核心指标</h4>
        <div className="metrics-grid">
          <MetricCard
            label="总运动距离"
            value={metrics.totalDistance}
            unit={scaleCalibration ? 'cm' : 'px'}
            icon="📏"
          />
          <MetricCard
            label="平均速度"
            value={metrics.avgSpeed}
            unit={scaleCalibration ? 'cm/s' : 'px/s'}
            icon="⚡"
          />
          <MetricCard
            label="中心区时间"
            value={metrics.centerTime}
            unit="s"
            icon="🎯"
          />
          <MetricCard
            label="穿越次数"
            value={metrics.entries}
            unit="次"
            icon="🔄"
          />
        </div>
      </div>

      <div className="visualization-section">
        <div className="tab-header">
          <button
            className={`tab-btn ${activeTab === 'trajectory' ? 'active' : ''}`}
            onClick={() => setActiveTab('trajectory')}
          >
            轨迹图
          </button>
          <button
            className={`tab-btn ${activeTab === 'heatmap' ? 'active' : ''}`}
            onClick={() => setActiveTab('heatmap')}
          >
            热力图
          </button>
        </div>
        
        <div className="tab-content">
          {activeTab === 'trajectory' ? (
            <TrajectoryChart 
              trajectory={trackingData?.trajectory} 
              videoInfo={null}
            />
          ) : (
            <HeatmapDisplay 
              rois={rois} 
              trackingData={trackingData}
              videoInfo={null}
            />
          )}
        </div>
      </div>

      <div className="export-section">
        <button
          className="btn btn-primary btn-block btn-export"
          onClick={handleExport}
          disabled={!trackingData || isExporting}
        >
          {isExporting ? (
            <>
              <span className="export-spinner"></span>
              导出中...
            </>
          ) : (
            <>
              <span className="export-icon">📊</span>
              一键导出分析报告
            </>
          )}
        </button>
        <p className="export-hint">
          支持导出 JSON / Excel 格式
        </p>
      </div>
    </div>
  );
};

export default DataPanel;
