import React, { useState, useEffect } from 'react';
import ConfigPanel from '../components/panels/ConfigPanel';
import MainWorkspace from '../components/panels/MainWorkspace';
import DataPanel from '../components/panels/DataPanel';

const TOOL_TYPES = {
  SELECT: 'select',
  RECTANGLE: 'rectangle',
  POLYGON: 'polygon',
  CIRCLE: 'circle'
};

const Workspace = ({ experimentType, onBack }) => {
  const [videoFile, setVideoFile] = useState(null);
  const [videoInfo, setVideoInfo] = useState(null);
  const [rois, setROIs] = useState([]);
  const [trackingData, setTrackingData] = useState(null);
  const [isTracking, setIsTracking] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [currentFrame, setCurrentFrame] = useState(0);
  const [subjectInfo, setSubjectInfo] = useState({
    id: '',
    group: '',
    weight: '',
    notes: ''
  });
  const [timeRange, setTimeRange] = useState({ start: 0, end: 0 });
  const [scaleCalibration, setScaleCalibration] = useState(null);
  const [algorithmParams, setAlgorithmParams] = useState({
    mog2History: 500,
    mog2VarThreshold: 50,
    minArea: 100,
    maxArea: 10000,
    mouseType: 'auto'
  });
  
  const [activeTool, setActiveTool] = useState(TOOL_TYPES.SELECT);
  const [history, setHistory] = useState([]);
  const [calibrationMode, setCalibrationMode] = useState(false);
  const [calibrationPoints, setCalibrationPoints] = useState([]);

  const [arenaConfig, setArenaConfig] = useState({
    enabled: false,
    arena: null,
    centerRatio: 30,
    showCorners: false,
    cornerRatio: 10
  });

  useEffect(() => {
    if (arenaConfig.arena && arenaConfig.enabled && videoInfo) {
      const arena = arenaConfig.arena;

      // arena is normalized (0~1), convert to video pixel coordinates
      const arenaX = arena.x * videoInfo.width;
      const arenaY = arena.y * videoInfo.height;
      const arenaWidth = arena.width * videoInfo.width;
      const arenaHeight = arena.height * videoInfo.height;

      const centerRatio = arenaConfig.centerRatio / 100;
      const centerWidth = arenaWidth * centerRatio;
      const centerHeight = arenaHeight * centerRatio;
      const centerX = arenaX + (arenaWidth - centerWidth) / 2;
      const centerY = arenaY + (arenaHeight - centerHeight) / 2;

      const centerZone = {
        id: 'center-zone',
        name: '中心区',
        type: 'rectangle',
        x: centerX,
        y: centerY,
        width: centerWidth,
        height: centerHeight,
        color: 'hsl(210, 70%, 50%)',
        isAutoGenerated: true,
        parentArena: arena.id
      };

      const cornerSize = Math.min(arenaWidth, arenaHeight) * (arenaConfig.cornerRatio / 100);
      const corners = arenaConfig.showCorners ? [
        {
          id: 'corner-tl',
          name: '左上角',
          type: 'rectangle',
          x: arenaX,
          y: arenaY,
          width: cornerSize,
          height: cornerSize,
          color: 'hsl(120, 70%, 50%)',
          isAutoGenerated: true,
          parentArena: arena.id
        },
        {
          id: 'corner-tr',
          name: '右上角',
          type: 'rectangle',
          x: arenaX + arenaWidth - cornerSize,
          y: arenaY,
          width: cornerSize,
          height: cornerSize,
          color: 'hsl(120, 70%, 50%)',
          isAutoGenerated: true,
          parentArena: arena.id
        },
        {
          id: 'corner-bl',
          name: '左下角',
          type: 'rectangle',
          x: arenaX,
          y: arenaY + arenaHeight - cornerSize,
          width: cornerSize,
          height: cornerSize,
          color: 'hsl(120, 70%, 50%)',
          isAutoGenerated: true,
          parentArena: arena.id
        },
        {
          id: 'corner-br',
          name: '右下角',
          type: 'rectangle',
          x: arenaX + arenaWidth - cornerSize,
          y: arenaY + arenaHeight - cornerSize,
          width: cornerSize,
          height: cornerSize,
          color: 'hsl(120, 70%, 50%)',
          isAutoGenerated: true,
          parentArena: arena.id
        }
      ] : [];

      const autoGeneratedROIs = [centerZone, ...corners];
      setROIs(prevROIs => {
        const userROIs = prevROIs.filter(roi => !roi.isAutoGenerated);
        return [...userROIs, ...autoGeneratedROIs];
      });
    }
  }, [arenaConfig, videoInfo]);

  const handleArenaChange = (newArenaConfig) => {
    setArenaConfig(newArenaConfig);
  };

  const handleToolChange = (tool) => {
    setActiveTool(tool);
  };

  const handleUndo = () => {
    if (history.length > 0) {
      const newHistory = [...history];
      const previousState = newHistory.pop();
      setHistory(newHistory);
      setROIs(previousState);
    }
  };

  const handleClear = () => {
    setHistory([...history, rois]);
    setROIs([]);
  };

  const handleCalibrationClick = (point) => {
    if (calibrationPoints.length < 2) {
      setCalibrationPoints([...calibrationPoints, point]);
    }
  };

  const handleCalibrationComplete = (length) => {
    if (calibrationPoints.length === 2 && length) {
      const pixelDistance = Math.sqrt(
        Math.pow(calibrationPoints[1].x - calibrationPoints[0].x, 2) +
        Math.pow(calibrationPoints[1].y - calibrationPoints[0].y, 2)
      );
      const pixelsPerCm = pixelDistance / parseFloat(length);
      setScaleCalibration({
        pixelsPerCm,
        points: calibrationPoints,
        realLength: parseFloat(length)
      });
      setCalibrationMode(false);
      setCalibrationPoints([]);
    }
  };

  return (
    <div className="workspace">
      <header className="workspace-header">
        <div className="header-left">
          <button className="btn-back" onClick={onBack}>
            ← 返回
          </button>
          <div className="experiment-info">
            <span className="experiment-icon">{experimentType.icon}</span>
            <span className="experiment-name">{experimentType.name}</span>
            <span className="experiment-name-en">{experimentType.nameEn}</span>
          </div>
        </div>
        <div className="header-actions">
          <button className="btn btn-secondary">保存项目</button>
          <button className="btn btn-primary">导出报告</button>
        </div>
      </header>
      
      <div className="workspace-content">
        <div className="panel panel-left">
          <ConfigPanel
            experimentType={experimentType}
            subjectInfo={subjectInfo}
            setSubjectInfo={setSubjectInfo}
            videoFile={videoFile}
            setVideoFile={setVideoFile}
            videoInfo={videoInfo}
            setVideoInfo={setVideoInfo}
            timeRange={timeRange}
            setTimeRange={setTimeRange}
            scaleCalibration={scaleCalibration}
            setScaleCalibration={setScaleCalibration}
            rois={rois}
            setROIs={setROIs}
            algorithmParams={algorithmParams}
            setAlgorithmParams={setAlgorithmParams}
            activeTool={activeTool}
            onToolChange={handleToolChange}
            onUndo={handleUndo}
            onClear={handleClear}
            canUndo={history.length > 0}
            calibrationMode={calibrationMode}
            setCalibrationMode={setCalibrationMode}
            calibrationPoints={calibrationPoints}
            setCalibrationPoints={setCalibrationPoints}
            onCalibrationComplete={handleCalibrationComplete}
            arenaConfig={arenaConfig}
            onArenaChange={handleArenaChange}
          />
        </div>
        
        <div className="panel panel-center">
          <MainWorkspace
            videoFile={videoFile}
            videoInfo={videoInfo}
            rois={rois}
            setROIs={setROIs}
            trackingData={trackingData}
            setTrackingData={setTrackingData}
            isTracking={isTracking}
            setIsTracking={setIsTracking}
            currentTime={currentTime}
            setCurrentTime={setCurrentTime}
            currentFrame={currentFrame}
            setCurrentFrame={setCurrentFrame}
            scaleCalibration={scaleCalibration}
            setScaleCalibration={setScaleCalibration}
            timeRange={timeRange}
            algorithmParams={algorithmParams}
            activeTool={activeTool}
            onToolChange={handleToolChange}
            onUndo={handleUndo}
            onClear={handleClear}
            history={history}
            setHistory={setHistory}
            calibrationMode={calibrationMode}
            calibrationPoints={calibrationPoints}
            onCalibrationClick={handleCalibrationClick}
            arenaConfig={arenaConfig}
            onArenaChange={handleArenaChange}
          />
        </div>
        
        <div className="panel panel-right">
          <DataPanel
            experimentType={experimentType}
            trackingData={trackingData}
            rois={rois}
            currentTime={currentTime}
            currentFrame={currentFrame}
            isTracking={isTracking}
            subjectInfo={subjectInfo}
            scaleCalibration={scaleCalibration}
            videoInfo={videoInfo}
          />
        </div>
      </div>
    </div>
  );
};

export default Workspace;
